var paydockConf={};paydockConf.host="https://api.paydock.com",paydockConf.sandboxHost="https://api-sandbox.paydock.com",paydockConf.versionApi="v1",paydockConf.resource="/payment_sources/tokens";var Paydock=function(conf){function createRequest(publicKey,useSandbox,config){var request=new XMLHttpRequest,host=useSandbox?config.sandboxHost:config.host;return host+="/"+config.versionApi+config.resource,request.open("POST",host,!0),request.setRequestHeader("Content-Type","application/json; charset=UTF-8"),request.setRequestHeader("x-user-public-key",publicKey),request}var Main=function(config){this.publicKey="",this.useSandbox=!1,this.config={host:"",sandboxHost:"",versionApi:"",resource:""},this.contact=function(a,b){var c={};for(var key in a)a.hasOwnProperty(key)&&(c[key]=key in b?b[key]:a[key]);return c},this.config=this.contact(this.config,config)};return Main.prototype.setPublicKey=function(publicKey){this.publicKey=publicKey},Main.prototype.setSandbox=function(use){this.useSandbox=use},Main.prototype.createToken=function(params,successCallback,errorCallback){var request=createRequest(this.publicKey,this.useSandbox,this.config);request.onload=function(){request.status>=200&&request.status<400?"function"==typeof successCallback&&successCallback(JSON.parse(request.responseText).resource.data,request.status):"function"==typeof successCallback&&errorCallback(JSON.parse(request.responseText).error,request.status)},request.send(JSON.stringify(params))},new Main(conf)}(paydockConf);